import Activity from '../Activity';
import Procedure from '../Procedure';
import Transition from '../Transition';

const fs = require('fs');
const path = require('path');

/**
 * A class for loading .flow files for introspection by the static-flow-analysis tools.
 * This is not used during Flow execution.
 * @class GojsLoader
 * @memberof module:jibo-flow-core.loaders
 * @intdocs
 */

class GojsLoader {
    procedures:{ [key:string]:Procedure };

    constructor() {
        this.procedures = {};
    }

    /**
     * Extract the procedure name part from the .flow file name.
     * @method jibo.flow.GojsLoader#getStartProcedureOrName
     * @param {string} uri Full name of .flow file.
     * @returns {string}
     */
    
    public getStartProcedureOrName(uri:string):string {
        return path.parse(uri).name;
    }

    public getUri(uri:string):string {
        return uri;
    }

    public getBase(uri:string):string {
        return path.parse(uri).dir;
    }

    /**
     * Return a Procedure given a path to an existing procedure and a procedure name relative to it.
     * @method jibo.flow.GojsLoader#loadProcedureRelative
     * @param {string} currentUri The existing procedure the name is relative to.
     * @param {string} name The relative name of the procedure to load.
     * @returns {jibo.flow.Procedure}
     */
    public loadProcedureRelative(currentUri:string, name:string) {
        let baseUri = this.getBase(currentUri);
        let uri = path.join(baseUri, name + '.flow');
        return this.loadProcedure(uri);
    }

    /**
     * Return a Procedure given an absolute path to it.
     * @method jibo.flow.GojsLoader#loadProcedure
     * @param {string} uri The absolute path to the procedure.
     * @returns {jibo.flow.Procedure}
     */
    public loadProcedure(uri:string):Procedure {
        let name = this.getStartProcedureOrName(uri);
        if (!this.procedures.hasOwnProperty(name)) {
            this.procedures[name] = this.readProcedure(name, uri);
        }
        return this.procedures[name];
    }

    /**
     * Read and construct a Procedure from a .flow file.
     * @method jibo.flow.GojsLoader#readProcedure
     * @param {string} name The name of the procedure being loaded (e.g. "main").
     * @param {string} uri The uri of the file being loaded (e.g. "src/flows/main.flow").
     * @returns {jibo.flow.Procedure}
     */
    public readProcedure(name:string, uri:string):Procedure {
        let data = fs.readFileSync(uri, 'utf8');
        let base = JSON.parse(data);

        let procedure = new Procedure(name, uri, {}, {});

        for (let i = 0; i < base.linkDataArray.length; i++) {
            let goLink = base.linkDataArray[i];
            let transitionValue = goLink.text === undefined ? "" : goLink.text;
            let transition = new Transition(goLink.from, goLink.to, transitionValue);
            procedure.add_transition(transition);
        }

        for (let i = 0; i < base.nodeDataArray.length; i++) {
            let goNode = base.nodeDataArray[i];
            let activity = new Activity(goNode.name, goNode.id, goNode.class, goNode['asset-pack'], goNode.options);
            procedure.add_activity(activity);
        }

        return procedure;
    }
}

export default GojsLoader;